  `check_out_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'NORMAL' COMMENT '下班打卡状态（NORMAL正常 EARLY早退 ABSENT缺卡）',
