  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `check_in_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '上班打卡位置（JSON格式）',
  `check_out_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '下班打卡位置（JSON格式）',
  `device_info` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '设备信息',
  `approve_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审批状态（PENDING待审批 APPROVED已通过 REJECTED已拒绝）',
  `approver_id` bigint(20) NULL DEFAULT NULL COMMENT '审批人ID',
  `approve_time` datetime NULL DEFAULT NULL COMMENT '审批时间',
  `approve_comment` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审批意见',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id`, `attendance_date`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_attendance_date`(`attendance_date`) USING BTREE,
  INDEX `idx_approve_status`(`approve_status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 73 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '考勤记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_group
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_group`;
CREATE TABLE `im_attendance_group`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '考勤组ID',
  `group_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '考勤组名称',
  `manager_id` bigint(20) NOT NULL COMMENT '考勤组负责人ID',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '考勤组描述',
  `attendance_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '考勤类型：FIXED固定班次, FLEXIBLE弹性班次, FREE自由打卡',
  `check_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '打卡方式：FACE人脸, LOCATION地理位置, WIFI Wi-Fi, MIXED混合',
  `work_start_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上班时间（HH:mm:ss）',
  `work_end_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '下班时间（HH:mm:ss）',
  `check_in_before` int(11) NULL DEFAULT NULL COMMENT '打卡有效开始时间（上班前多少分钟有效）',
  `late_tolerance` int(11) NULL DEFAULT NULL COMMENT '晚到容忍时间（分钟）',
  `early_tolerance` int(11) NULL DEFAULT NULL COMMENT '早退容忍时间（分钟）',
  `work_days` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '工作日配置（JSON：1-7表示周一到周日）',
  `need_check_in` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否需要打卡',
  `allow_remote` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否允许外勤打卡',
  `check_range` int(11) NULL DEFAULT NULL COMMENT '打卡有效范围（米）',
  `check_location` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '打卡地点（JSON格式：经纬度、地址）',
  `wifi_ssid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Wi-Fi名称（当打卡方式包含WIFI时）',
  `auto_attendance` tinyint(1) NOT NULL DEFAULT 0 COMMENT '自动考勤',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态：ACTIVE启用, DISABLED禁用',
  `creator_id` bigint(20) NOT NULL COMMENT '创建人ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_manager_id`(`manager_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤组表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_group
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_group_member
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_group_member`;
CREATE TABLE `im_attendance_group_member`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '成员ID',
  `group_id` bigint(20) NOT NULL COMMENT '考勤组ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名称（冗余）',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MEMBER' COMMENT '成员角色：ADMIN管理员, MEMBER普通成员',
  `join_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '入组时间',
  `leave_time` datetime NULL DEFAULT NULL COMMENT '离组时间',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态：ACTIVE在职, LEFT已离组',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤组成员表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_group_member
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_holiday
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_holiday`;
CREATE TABLE `im_attendance_holiday`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '假期ID',
  `holiday_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '假期名称',
  `holiday_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '假期类型：LEGAL法定假期, ADJUSTMENT调休, CUSTOM自定义',
  `start_date` date NOT NULL COMMENT '开始日期',
  `end_date` date NOT NULL COMMENT '结束日期',
  `days` int(11) NOT NULL COMMENT '天数',
  `is_workday` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否需要上班（调休时为true）',
  `year` int(11) NOT NULL COMMENT '年份',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_year`(`year`) USING BTREE,
  INDEX `idx_date_range`(`start_date`, `end_date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤假期表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_holiday
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_schedule
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_schedule`;
CREATE TABLE `im_attendance_schedule`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '排班ID',
  `group_id` bigint(20) NOT NULL COMMENT '考勤组ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `shift_id` bigint(20) NULL DEFAULT NULL COMMENT '班次ID',
  `schedule_date` date NOT NULL COMMENT '排班日期',
  `schedule_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '排班类型：WORK工作日, REST休息日, HOLIDAY法定假日',
  `need_check_in` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否需要打卡',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id`, `schedule_date`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_schedule_date`(`schedule_date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤排班表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_schedule
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_shift
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_shift`;
CREATE TABLE `im_attendance_shift`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '班次ID',
  `group_id` bigint(20) NOT NULL COMMENT '考勤组ID',
  `shift_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '班次名称',
  `shift_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '班次类型：NORMAL正常班, NIGHT夜班, FLEXIBLE弹性班',
  `work_start_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上班时间（HH:mm:ss）',
  `work_end_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '下班时间（HH:mm:ss）',
  `check_in_before` int(11) NULL DEFAULT NULL COMMENT '打卡有效开始时间（上班前多少分钟）',
  `check_out_after` int(11) NULL DEFAULT NULL COMMENT '打卡有效结束时间（下班后多少分钟）',
  `late_tolerance` int(11) NULL DEFAULT NULL COMMENT '晚到容忍时间（分钟）',
  `early_tolerance` int(11) NULL DEFAULT NULL COMMENT '早退容忍时间（分钟）',
  `break_start_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '休息开始时间（HH:mm:ss）',
  `break_end_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '休息结束时间（HH:mm:ss）',
  `work_minutes` int(11) NULL DEFAULT NULL COMMENT '工作时长（分钟）',
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '颜色标识',
  `sort_order` int(11) NOT NULL DEFAULT 0 COMMENT '排序号',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态：ACTIVE启用, DISABLED禁用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤班次表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_shift
-- ----------------------------

-- ----------------------------
-- Table structure for im_attendance_statistics
-- ----------------------------
DROP TABLE IF EXISTS `im_attendance_statistics`;
CREATE TABLE `im_attendance_statistics`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '统计ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `statistics_month` char(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '统计年月（yyyy-MM）',
  `attendance_days` int(11) NULL DEFAULT 0 COMMENT '出勤天数',
  `leave_days` int(11) NULL DEFAULT 0 COMMENT '请假天数',
  `overtime_days` int(11) NULL DEFAULT 0 COMMENT '加班天数',
  `late_count` int(11) NULL DEFAULT 0 COMMENT '迟到次数',
  `early_count` int(11) NULL DEFAULT 0 COMMENT '早退次数',
  `absent_count` int(11) NULL DEFAULT 0 COMMENT '缺卡次数',
  `actual_work_hours` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '实际工作时长（小时）',
  `standard_work_hours` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '标准工作时长（小时）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_month`(`user_id`, `statistics_month`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_statistics_month`(`statistics_month`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '考勤统计表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_attendance_statistics
-- ----------------------------

-- ----------------------------
-- Table structure for im_audit_export_request
-- ----------------------------
DROP TABLE IF EXISTS `im_audit_export_request`;
CREATE TABLE `im_audit_export_request`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '请求ID',
  `user_id` bigint(20) NOT NULL COMMENT '申请人ID',
  `export_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '导出类型: MESSAGE消息 FILE文件 USER用户',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '导出原因',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态: PENDING待审批 APPROVED已批准 REJECTED已拒绝 EXPIRED已过期',
  `approver_id` bigint(20) NULL DEFAULT NULL COMMENT '审批人ID',
  `approved_time` datetime NULL DEFAULT NULL COMMENT '审批时间',
  `approval_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审批备注',
  `export_file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '导出文件路径',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_approver_id`(`approver_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1120 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '审计导出请求表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_audit_export_request
-- ----------------------------

-- ----------------------------
-- Table structure for im_audit_log
-- ----------------------------
DROP TABLE IF EXISTS `im_audit_log`;
CREATE TABLE `im_audit_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `user_id` bigint(20) NULL DEFAULT NULL COMMENT '操作用户ID',
  `operation_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作类型: LOGIN登录 LOGOUT登出 SEND_MESSAGE发送消息 DELETE_MESSAGE删除消息 CREATE_GROUP创建群组 JOIN_GROUP加入群组 LEAVE_GROUP退出群组 ADD_FRIEND添加好友 DELETE_FRIEND删除好友等',
  `target_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '目标类型: USER用户 MESSAGE消息 GROUP群组 CONVERSATION会话 FRIEND好友',
  `target_id` bigint(20) NULL DEFAULT NULL COMMENT '目标ID',
  `operation_result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SUCCESS' COMMENT '操作结果: SUCCESS成功 FAILED失败',
  `error_message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '错误信息',
  `ip_address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户代理',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_operation_type`(`operation_type`) USING BTREE,
  INDEX `idx_target_type`(`target_type`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `idx_operation_result`(`operation_result`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12079 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '审计日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_audit_log
-- ----------------------------

-- ----------------------------
-- Table structure for im_backup
-- ----------------------------
DROP TABLE IF EXISTS `im_backup`;
CREATE TABLE `im_backup`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '备份ID',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '备份文件名',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备份描述',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件路径',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小',
  `backup_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '备份类型',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '状态',
  `creator_id` bigint(20) NULL DEFAULT NULL COMMENT '备份人ID',
  `creator_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备份人名称',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '错误信息（失败时记录）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `complete_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_backup_type`(`backup_type`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `idx_creator_id`(`creator_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 121 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '数据备份表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_backup
-- ----------------------------

-- ----------------------------
-- Table structure for im_chat_background
-- ----------------------------
DROP TABLE IF EXISTS `im_chat_background`;
CREATE TABLE `im_chat_background`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `conversation_id` bigint(20) NULL DEFAULT NULL COMMENT '会话ID（NULL表示全局背景）',
  `background_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'default' COMMENT '背景类型：default默认 color纯色 image图片',
  `background_value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '背景值（颜色值或图片URL）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_conversation`(`user_id`, `conversation_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '聊天背景设置表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_chat_background
-- ----------------------------

-- ----------------------------
-- Table structure for im_cloud_file
-- ----------------------------
DROP TABLE IF EXISTS `im_cloud_file`;
CREATE TABLE `im_cloud_file`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '文件ID',
  `file_asset_id` bigint(20) NULL DEFAULT NULL COMMENT '关联的文件资产ID',
  `folder_id` bigint(20) NOT NULL COMMENT '所在文件夹ID',
  `file_name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名称（可包含后缀）',
  `file_size` bigint(20) NOT NULL DEFAULT 0 COMMENT '文件大小（字节）',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件类型：document文档, image图片, video视频, audio音频, archive压缩包, other其他',
  `file_ext` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件扩展名',
  `mime_type` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'MIME类型',
  `uploader_id` bigint(20) NOT NULL COMMENT '上传者ID',
  `uploader_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上传者名称（冗余）',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件标签（逗号分隔）',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '文件描述',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `preview_count` int(11) NOT NULL DEFAULT 0 COMMENT '预览权次数',
  `access_permission` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PRIVATE' COMMENT '访问权限：PRIVATE私有, DEPARTMENT部门可见, PUBLIC公开',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已删除',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_folder_id`(`folder_id`) USING BTREE,
  INDEX `idx_uploader_id`(`uploader_id`) USING BTREE,
  INDEX `idx_file_type`(`file_type`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '企业云盘文件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_cloud_file
-- ----------------------------

-- ----------------------------
-- Table structure for im_cloud_file_share
-- ----------------------------
DROP TABLE IF EXISTS `im_cloud_file_share`;
CREATE TABLE `im_cloud_file_share`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '分享ID',
  `share_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分享类型：FILE文件, FOLDER文件夹',
  `resource_id` bigint(20) NOT NULL COMMENT '文件或文件夹ID',
  `sharer_id` bigint(20) NOT NULL COMMENT '分享者ID',
  `share_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分享码（唯一）',
  `share_link` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分享链接',
  `access_password` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '访问密码',
  `expire_days` int(11) NOT NULL DEFAULT 0 COMMENT '有效期天数，0表示永久',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `allow_download` tinyint(1) NOT NULL DEFAULT 1 COMMENT '允许下载：true允许, false禁止',
  `allow_preview` tinyint(1) NOT NULL DEFAULT 1 COMMENT '允许预览：true允许, false禁止',
  `view_count` int(11) NOT NULL DEFAULT 0 COMMENT '访问次数',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态：ACTIVE有效, EXPIRED已过期, CANCELLED已取消',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_share_code`(`share_code`) USING BTREE,
  INDEX `idx_sharer_id`(`sharer_id`) USING BTREE,
  INDEX `idx_resource`(`share_type`, `resource_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '企业云盘文件分享表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_cloud_file_share
-- ----------------------------

-- ----------------------------
-- Table structure for im_cloud_file_version
-- ----------------------------
DROP TABLE IF EXISTS `im_cloud_file_version`;
CREATE TABLE `im_cloud_file_version`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '版本ID',
  `cloud_file_id` bigint(20) NOT NULL COMMENT '云盘文件ID',
  `file_asset_id` bigint(20) NOT NULL COMMENT '文件资产ID',
  `version_number` int(11) NOT NULL COMMENT '版本号',
  `version_note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '版本说明',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小',
  `operator_id` bigint(20) NOT NULL COMMENT '操作者ID',
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作者名称（冗余）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_cloud_file_id`(`cloud_file_id`) USING BTREE,
  INDEX `idx_version_number`(`cloud_file_id`, `version_number`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '企业云盘文件版本表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_cloud_file_version
-- ----------------------------

-- ----------------------------
-- Table structure for im_cloud_folder
-- ----------------------------
DROP TABLE IF EXISTS `im_cloud_folder`;
CREATE TABLE `im_cloud_folder`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '文件夹ID',
  `folder_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件夹名称',
  `parent_id` bigint(20) NOT NULL DEFAULT 0 COMMENT '父文件夹ID，0表示根目录',
  `owner_id` bigint(20) NOT NULL COMMENT '所有者ID',
  `owner_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '所有者类型：USER个人, DEPARTMENT部门, COMPANY公司',
  `department_id` bigint(20) NULL DEFAULT NULL COMMENT '部门ID（当owner_type为DEPARTMENT时）',
  `folder_path` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件夹路径',
  `level` int(11) NOT NULL DEFAULT 0 COMMENT '层级深度',
  `sort_order` int(11) NOT NULL DEFAULT 0 COMMENT '排序号',
  `access_permission` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PRIVATE' COMMENT '访问权限：PRIVATE私有, DEPARTMENT部门可见, PUBLIC公开',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已删除',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE,
  INDEX `idx_owner_id`(`owner_id`, `owner_type`) USING BTREE,
  INDEX `idx_department_id`(`department_id`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '企业云盘文件夹表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_cloud_folder
-- ----------------------------

-- ----------------------------
-- Table structure for im_conversation
-- ----------------------------
DROP TABLE IF EXISTS `im_conversation`;
CREATE TABLE `im_conversation`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '会话ID',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '类型: PRIVATE私聊 GROUP群聊',
  `target_id` bigint(20) NULL DEFAULT NULL COMMENT '目标ID(私聊时为对方用户ID,群聊时为群组ID)',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '会话名称',
  `avatar` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '会话头像',
  `last_message_id` bigint(20) NULL DEFAULT NULL COMMENT '最后一条消息ID',
  `last_message_time` datetime NULL DEFAULT NULL COMMENT '最后消息时间',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除: 0否 1是',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_sensitive` tinyint(4) NULL DEFAULT 0 COMMENT '是否敏感会话：0=否, 1=是',
  `sensitive_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'NORMAL' COMMENT '敏感级别：NORMAL=普通, CONFIDENTIAL=机密, SECRET=绝密',
  `no_forward` tinyint(4) NULL DEFAULT 0 COMMENT '禁止转发：0=允许, 1=禁止',
  `no_copy` tinyint(4) NULL DEFAULT 0 COMMENT '禁止复制：0=允许, 1=禁止',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_type`(`type`) USING BTREE,
  INDEX `idx_target_id`(`target_id`) USING BTREE,
  INDEX `idx_type_target`(`type`, `target_id`) USING BTREE,
  INDEX `idx_last_message_time`(`last_message_time`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 86 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会话表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_conversation
-- ----------------------------

-- ----------------------------
-- Table structure for im_conversation_member
-- ----------------------------
DROP TABLE IF EXISTS `im_conversation_member`;
CREATE TABLE `im_conversation_member`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '成员ID',
  `conversation_id` bigint(20) NOT NULL COMMENT '会话ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '群昵称',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MEMBER' COMMENT '角色: OWNER所有者 MEMBER成员',
  `unread_count` int(11) NOT NULL DEFAULT 0 COMMENT '未读数',
  `is_pinned` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否置顶: 0否 1是',
  `pinned_time` datetime NULL DEFAULT NULL COMMENT '置顶时间',
  `is_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否免打扰: 0否 1是',
  `last_read_message_id` bigint(20) NULL DEFAULT NULL COMMENT '最后已读消息ID',
  `last_read_time` datetime NULL DEFAULT NULL COMMENT '最后已读时间',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除: 0否 1是',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_archived` tinyint(4) NULL DEFAULT 0 COMMENT '是否归档：0=否, 1=是',
  `draft_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '草稿内容',
  `draft_time` datetime NULL DEFAULT NULL COMMENT '草稿保存时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_conversation_user`(`conversation_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_unread_count`(`unread_count`) USING BTREE,
  INDEX `idx_is_pinned`(`is_pinned`) USING BTREE,
  INDEX `idx_is_muted`(`is_muted`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE,
  INDEX `idx_update_time`(`update_time`) USING BTREE,
  INDEX `idx_user_archived`(`user_id`, `is_archived`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 670 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会话成员表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_conversation_member
-- ----------------------------

-- ----------------------------
-- Table structure for im_conversation_setting
-- ----------------------------
DROP TABLE IF EXISTS `im_conversation_setting`;
CREATE TABLE `im_conversation_setting`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `conversation_id` bigint(20) NOT NULL COMMENT '会话ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `is_pinned` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否置顶: 0否 1是',
  `pinned_time` datetime NULL DEFAULT NULL COMMENT '置顶时间',
  `is_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否免打扰: 0否 1是',
  `is_archived` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否归档: 0否 1是',
  `draft_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '草稿内容',
  `draft_time` datetime NULL DEFAULT NULL COMMENT '草稿保存时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_conversation_user`(`conversation_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_is_pinned`(`is_pinned`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会话用户设置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_conversation_setting
-- ----------------------------

-- ----------------------------
-- Table structure for im_conversation_sync_point
-- ----------------------------
DROP TABLE IF EXISTS `im_conversation_sync_point`;
CREATE TABLE `im_conversation_sync_point`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT '用户ID',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设备ID',
  `last_sync_time` bigint(20) UNSIGNED NOT NULL DEFAULT 0 COMMENT '最后同步时间戳(毫秒)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_device`(`user_id`, `device_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_update_time`(`update_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'IM会话同步点表' ROW_FORMAT = Dynamic;

