-- Records of im_ding_template
-- ----------------------------

-- ----------------------------
-- Table structure for im_document
-- ----------------------------
DROP TABLE IF EXISTS `im_document`;
CREATE TABLE `im_document`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '文档ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文档标题',
  `doc_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'doc' COMMENT '文档类型（doc=文档, sheet=表格, mind=思维导图）',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '文档内容（HTML/JSON格式）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'draft' COMMENT '文档状态（draft=草稿, published=已发布, archived=已归档）',
  `owner_id` bigint(20) NOT NULL COMMENT '所有者ID',
  `folder_id` bigint(20) NULL DEFAULT NULL COMMENT '所属文件夹ID',
  `is_starred` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否收藏',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除（回收站）',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `auto_delete_days` int(11) NULL DEFAULT NULL COMMENT '自动删除天数（回收站）',
  `last_modified_by` bigint(20) NULL DEFAULT NULL COMMENT '最后修改者ID',
  `last_modified_time` datetime NULL DEFAULT NULL COMMENT '最后修改时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `version` int(11) NOT NULL DEFAULT 1 COMMENT '版本号',
  `parent_id` bigint(20) NULL DEFAULT NULL COMMENT '父文档ID（用于文档关联）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_owner_id`(`owner_id`) USING BTREE,
  INDEX `idx_folder_id`(`folder_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '在线文档表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document
-- ----------------------------

-- ----------------------------
-- Table structure for im_document_collaborator
-- ----------------------------
DROP TABLE IF EXISTS `im_document_collaborator`;
CREATE TABLE `im_document_collaborator`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '协作者ID',
  `document_id` bigint(20) NOT NULL COMMENT '文档ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名称（冗余）',
  `user_avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户头像（冗余）',
  `permission` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '协作权限：EDIT编辑, COMMENT评论, VIEW查看',
  `inviter_id` bigint(20) NULL DEFAULT NULL COMMENT '邀请者ID',
  `join_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '加入时间',
  `last_active_time` datetime NULL DEFAULT NULL COMMENT '最后活跃时间',
  `online_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'OFFLINE' COMMENT '在线状态：ONLINE在线, OFFLINE离线',
  `cursor_position` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '光标位置（JSON格式）',
  `selection_range` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '当前选择范围（JSON格式）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_document_user`(`document_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_online_status`(`online_status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文档协作者表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document_collaborator
-- ----------------------------

-- ----------------------------
-- Table structure for im_document_comment
-- ----------------------------
DROP TABLE IF EXISTS `im_document_comment`;
CREATE TABLE `im_document_comment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '评论ID',
  `document_id` bigint(20) NOT NULL COMMENT '文档ID',
  `user_id` bigint(20) NOT NULL COMMENT '评论者ID',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评论内容',
  `parent_id` bigint(20) NULL DEFAULT NULL COMMENT '父评论ID（用于回复）',
  `selected_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '选中的文本（用于高亮评论）',
  `selection_offset` int(11) NULL DEFAULT NULL COMMENT '选中文本的偏移量',
  `is_resolved` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已解决',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_document_id`(`document_id`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文档评论表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document_comment
-- ----------------------------

-- ----------------------------
-- Table structure for im_document_operation_log
-- ----------------------------
DROP TABLE IF EXISTS `im_document_operation_log`;
CREATE TABLE `im_document_operation_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `document_id` bigint(20) NOT NULL COMMENT '文档ID',
  `user_id` bigint(20) NOT NULL COMMENT '操作用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名称（冗余）',
  `operation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作类型：INSERT插入, DELETE删除, UPDATE修改, FORMAT格式化',
  `position` int(11) NULL DEFAULT NULL COMMENT '操作位置（偏移量）',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '操作内容（被删除/插入的内容）',
  `content_length` int(11) NULL DEFAULT NULL COMMENT '内容长度',
  `before_version` int(11) NULL DEFAULT NULL COMMENT '操作前的版本号',
  `after_version` int(11) NULL DEFAULT NULL COMMENT '操作后的版本号',
  `change_summary` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '变更摘要',
  `operation_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '操作时间',
  `ip_address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户代理',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_document_id`(`document_id`) USING BTREE,
  INDEX `idx_operation_time`(`operation_time`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文档操作日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document_operation_log
-- ----------------------------

-- ----------------------------
-- Table structure for im_document_share
-- ----------------------------
DROP TABLE IF EXISTS `im_document_share`;
CREATE TABLE `im_document_share`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '分享ID',
  `document_id` bigint(20) NOT NULL COMMENT '文档ID',
  `shared_to_user_id` bigint(20) NOT NULL COMMENT '分享给的用户ID',
  `shared_by_user_id` bigint(20) NOT NULL COMMENT '分享者ID',
  `permission` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '权限（view=查看, edit=编辑, admin=管理）',
  `is_expired` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否过期',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_document_id`(`document_id`) USING BTREE,
  INDEX `idx_shared_to`(`shared_to_user_id`) USING BTREE,
  INDEX `idx_shared_by`(`shared_by_user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文档分享表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document_share
-- ----------------------------

-- ----------------------------
-- Table structure for im_document_version
-- ----------------------------
DROP TABLE IF EXISTS `im_document_version`;
CREATE TABLE `im_document_version`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '版本ID',
  `document_id` bigint(20) NOT NULL COMMENT '文档ID',
  `version` int(11) NOT NULL COMMENT '版本号',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '文档内容',
  `title_snapshot` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文档标题快照',
  `modified_by` bigint(20) NOT NULL COMMENT '修改者ID',
  `modified_by_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改者名称',
  `change_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改说明',
  `file_size` bigint(20) NULL DEFAULT NULL COMMENT '文件大小（字节）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_document_id`(`document_id`) USING BTREE,
  INDEX `idx_version`(`document_id`, `version`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文档版本表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_document_version
-- ----------------------------

-- ----------------------------
-- Table structure for im_e2e_key
-- ----------------------------
DROP TABLE IF EXISTS `im_e2e_key`;
CREATE TABLE `im_e2e_key`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `public_key` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '公钥',
  `key_version` int(11) NULL DEFAULT 1 COMMENT '密钥版本',
  `key_algorithm` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'RSA' COMMENT '密钥算法',
  `key_size` int(11) NULL DEFAULT 2048 COMMENT '密钥长度',
  `is_active` tinyint(4) NULL DEFAULT 1 COMMENT '是否激活',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_version`(`user_id`, `key_version`) USING BTREE,
  INDEX `idx_user_active`(`user_id`, `is_active`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '端到端加密密钥表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_e2e_key
-- ----------------------------

-- ----------------------------
-- Table structure for im_email
-- ----------------------------
DROP TABLE IF EXISTS `im_email`;
CREATE TABLE `im_email`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `sender_id` bigint(20) NULL DEFAULT NULL COMMENT '发送者ID',
  `sender_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发送者名称',
  `sender_email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发送者邮箱',
  `receiver_id` bigint(20) NULL DEFAULT NULL COMMENT '接收者ID',
  `cc_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '抄送ID列表(JSON)',
  `bcc_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '密送ID列表(JSON)',
  `reply_to_email_id` bigint(20) NULL DEFAULT NULL COMMENT '回复的原邮件ID',
  `forward_from_email_id` bigint(20) NULL DEFAULT NULL COMMENT '转发的原邮件ID',
  `subject` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邮件主题',
  `html_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '邮件内容（HTML格式）',
  `text_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '纯文本内容',
  `is_read` tinyint(1) NULL DEFAULT 0 COMMENT '是否已读',
  `is_deleted` tinyint(1) NULL DEFAULT 0 COMMENT '是否已删除（软删除）',
  `is_starred` tinyint(1) NULL DEFAULT 0 COMMENT '是否星标',
  `folder` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'INBOX' COMMENT '邮件文件夹：INBOX/SENT/DRAFTS/SPAM/TRASH',
  `draft_status` tinyint(1) NULL DEFAULT 0 COMMENT '草稿状态: 0-非草稿, 1-草稿中, 2-已发送',
  `draft_saved_at` datetime NULL DEFAULT NULL COMMENT '草稿最后保存时间',
  `draft_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '草稿临时内容（JSON格式）',
  `attachment_count` int(11) NULL DEFAULT 0 COMMENT '附件数量',
  `send_time` datetime NULL DEFAULT NULL COMMENT '发送时间',
  `receive_time` datetime NULL DEFAULT NULL COMMENT '接收时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_receiver_id`(`receiver_id`) USING BTREE,
  INDEX `idx_sender_id`(`sender_id`) USING BTREE,
  INDEX `idx_folder`(`folder`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `idx_receiver_folder`(`receiver_id`, `folder`) USING BTREE,
  INDEX `idx_receiver_read_deleted`(`receiver_id`, `is_read`, `is_deleted`) USING BTREE,
  INDEX `idx_draft_status`(`draft_status`) USING BTREE,
  INDEX `idx_sender_draft`(`sender_id`, `draft_status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 230 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邮件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_email
-- ----------------------------

-- ----------------------------
-- Table structure for im_email_attachment
-- ----------------------------
DROP TABLE IF EXISTS `im_email_attachment`;
CREATE TABLE `im_email_attachment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '附件ID',
  `email_id` bigint(20) NULL DEFAULT NULL COMMENT '邮件ID',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名',
  `file_size` bigint(20) NULL DEFAULT 0 COMMENT '文件大小(字节)',
  `file_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件类型(MIME)',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件存储路径',
  `file_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件访问URL',
  `upload_time` datetime NULL DEFAULT NULL COMMENT '上传时间',
  `uploader_id` bigint(20) NULL DEFAULT NULL COMMENT '上传者ID',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_email_id`(`email_id`) USING BTREE,
  INDEX `idx_uploader_id`(`uploader_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邮件附件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_email_attachment
-- ----------------------------

-- ----------------------------
-- Table structure for im_email_template
-- ----------------------------
DROP TABLE IF EXISTS `im_email_template`;
CREATE TABLE `im_email_template`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '模板ID',
  `template_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '模板名称',
  `template_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '模板编码',
  `subject` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '模板主题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '模板内容（支持变量替换）',
  `template_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SYSTEM' COMMENT '模板类型: SYSTEM-系统模板, USER-用户自定义',
  `scope` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ALL' COMMENT '适用范围: ALL-全部, INTERNAL-内部, EXTERNAL-外部',
  `variables` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '变量说明（JSON格式）',
  `is_enabled` int(11) NOT NULL DEFAULT 1 COMMENT '是否启用: 0-禁用, 1-启用',
  `usage_count` int(11) NOT NULL DEFAULT 0 COMMENT '使用次数',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分类',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_template_code`(`template_code`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE,
  INDEX `idx_template_type`(`template_type`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邮件模板表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_email_template
-- ----------------------------

-- ----------------------------
-- Table structure for im_emoji
-- ----------------------------
DROP TABLE IF EXISTS `im_emoji`;
CREATE TABLE `im_emoji`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '表情ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '表情名称',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '表情分类',
  `url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '表情图片URL',
  `shortcut` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '快捷方式',
  `width` int(11) NULL DEFAULT NULL COMMENT '表情宽度',
  `height` int(11) NULL DEFAULT NULL COMMENT '表情高度',
  `is_system` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否系统表情: 0否 1是',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '状态: 0禁用 1启用',
  `sort_order` int(11) NOT NULL DEFAULT 0 COMMENT '排序',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 99 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '表情包表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_emoji
-- ----------------------------

-- ----------------------------
-- Table structure for im_external_contact
-- ----------------------------
DROP TABLE IF EXISTS `im_external_contact`;
CREATE TABLE `im_external_contact`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '联系人ID',
  `user_id` bigint(20) NOT NULL COMMENT '所属用户ID',
  `group_id` bigint(20) NULL DEFAULT NULL COMMENT '分组ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系人姓名',
  `company` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `position` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '职位',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '手机号',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邮箱',
  `wechat` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '微信号',
  `address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '地址',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标签（多个标签用逗号分隔）',
  `avatar` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '头像',
  `is_starred` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否星标（0否 1是）',
  `source` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MANUAL' COMMENT '来源（MANUAL手动 IMPORT导入 SHARE分享）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_mobile`(`mobile`) USING BTREE,
  INDEX `idx_email`(`email`) USING BTREE,
  INDEX `idx_is_starred`(`is_starred`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 65 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '外部联系人表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_external_contact
-- ----------------------------

-- ----------------------------
-- Table structure for im_external_contact_group
-- ----------------------------
DROP TABLE IF EXISTS `im_external_contact_group`;
CREATE TABLE `im_external_contact_group`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '分组ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分组名称',
  `sort_order` int(11) NOT NULL DEFAULT 0 COMMENT '排序',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_sort_order`(`sort_order`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '外部联系人分组表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_external_contact_group
-- ----------------------------

-- ----------------------------
-- Table structure for im_file_asset
-- ----------------------------
DROP TABLE IF EXISTS `im_file_asset`;
CREATE TABLE `im_file_asset`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '文件ID',
  `file_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件路径',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小(字节)',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件类型',
  `file_ext` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件扩展名',
  `md5` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件MD5值',
  `uploader_id` bigint(20) NOT NULL COMMENT '上传者ID',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `download_expire_time` datetime NULL DEFAULT NULL COMMENT '下载过期时间',
  `status` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态: ACTIVE正常 DELETED已删除',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_uploader_id`(`uploader_id`) USING BTREE,
  INDEX `idx_md5`(`md5`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1111 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文件资源表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_file_asset
-- ----------------------------

-- ----------------------------
-- Table structure for im_file_chunk_detail
-- ----------------------------
DROP TABLE IF EXISTS `im_file_chunk_detail`;
CREATE TABLE `im_file_chunk_detail`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `upload_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上传ID',
  `chunk_number` int(11) NOT NULL COMMENT '分片序号（从1开始）',
  `chunk_size` int(11) NOT NULL COMMENT '分片大小（字节）',
  `chunk_md5` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分片MD5值',
  `chunk_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分片文件存储路径',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态：PENDING待上传、UPLOADING上传中、COMPLETED已完成',
  `retry_count` int(11) NOT NULL DEFAULT 0 COMMENT '重试次数',
  `error_message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '错误信息',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_upload_chunk`(`upload_id`, `chunk_number`) USING BTREE,
  INDEX `idx_upload_id`(`upload_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '分片文件详情表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_file_chunk_detail
-- ----------------------------

-- ----------------------------
-- Table structure for im_file_chunk_upload
-- ----------------------------
DROP TABLE IF EXISTS `im_file_chunk_upload`;
CREATE TABLE `im_file_chunk_upload`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `upload_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上传ID（唯一标识一次上传任务）',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '原始文件名',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小（字节）',
  `file_md5` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件MD5值',
  `chunk_size` int(11) NOT NULL COMMENT '分片大小（字节）',
  `total_chunks` int(11) NOT NULL COMMENT '总分片数',
  `uploaded_chunks` int(11) NOT NULL DEFAULT 0 COMMENT '已上传分片数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'UPLOADING' COMMENT '状态：UPLOADING上传中、PAUSED已暂停、COMPLETED已完成、CANCELLED已取消',
  `user_id` bigint(20) NOT NULL COMMENT '上传用户ID',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '最终文件路径',
  `file_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '最终文件URL',
  `error_message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '错误信息',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_upload_id`(`upload_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_md5`(`file_md5`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '分片上传记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_file_chunk_upload
-- ----------------------------

-- ----------------------------
-- Table structure for im_file_share
-- ----------------------------
DROP TABLE IF EXISTS `im_file_share`;
CREATE TABLE `im_file_share`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '分享ID',
  `file_id` bigint(20) NOT NULL COMMENT '文件ID',
  `sharer_id` bigint(20) NOT NULL COMMENT '分享者ID',
  `receiver_ids` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '接收者ID，多个接收者用逗号分隔',
  `permission` int(11) NOT NULL DEFAULT 1 COMMENT '分享权限: 1=公开, 2=指定人可见, 3=密码保护',
  `access_password` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '访问密码',
  `allow_download` tinyint(1) NOT NULL DEFAULT 1 COMMENT '允许下载: 0=否, 1=是',
  `allow_preview` tinyint(1) NOT NULL DEFAULT 1 COMMENT '允许预览: 0=否, 1=是',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `access_count` int(11) NOT NULL DEFAULT 0 COMMENT '访问次数',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_file_id`(`file_id`) USING BTREE,
  INDEX `idx_sharer_id`(`sharer_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '文件分享记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_file_share
-- ----------------------------

-- ----------------------------
-- Table structure for im_forward_audit_log
-- ----------------------------
DROP TABLE IF EXISTS `im_forward_audit_log`;
CREATE TABLE `im_forward_audit_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `message_id` bigint(20) NOT NULL COMMENT '原消息ID',
  `original_conversation_id` bigint(20) NOT NULL COMMENT '原会话ID',
  `target_conversation_id` bigint(20) NOT NULL COMMENT '目标会话ID',
  `forward_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '转发类型：SINGLE=逐条, COMBINE=合并',
  `operator_id` bigint(20) NOT NULL COMMENT '操作人ID',
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '操作人姓名',
  `operator_ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '操作人IP',
  `forward_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '转发时间',
  `content_preview` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '内容预览',
  `result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'SUCCESS' COMMENT '结果：SUCCESS=成功, DENIED=拒绝, FAILED=失败',
  `deny_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拒绝原因',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_message_id`(`message_id`) USING BTREE,
  INDEX `idx_operator_id`(`operator_id`) USING BTREE,
  INDEX `idx_forward_time`(`forward_time`) USING BTREE,
  INDEX `idx_original_conversation`(`original_conversation_id`) USING BTREE,
  INDEX `idx_target_conversation`(`target_conversation_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '消息转发审计日志表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_forward_audit_log
-- ----------------------------

-- ----------------------------
-- Table structure for im_friend
-- ----------------------------
DROP TABLE IF EXISTS `im_friend`;
CREATE TABLE `im_friend`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '关系ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `friend_id` bigint(20) NOT NULL COMMENT '好友ID',
  `remark` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注名',
  `group_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分组名',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除: 0否 1是',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '好友标签，多个标签用逗号分隔',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_friend`(`user_id`, `friend_id`) USING BTREE,
  INDEX `idx_friend_id`(`friend_id`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2622 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '好友关系表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_friend
-- ----------------------------

-- ----------------------------
-- Table structure for im_friend_request
-- ----------------------------
DROP TABLE IF EXISTS `im_friend_request`;
CREATE TABLE `im_friend_request`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '申请ID',
  `from_user_id` bigint(20) NOT NULL COMMENT '申请人ID',
  `to_user_id` bigint(20) NOT NULL COMMENT '接收人ID',
  `message` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '申请消息',
  `status` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态: PENDING待处理 APPROVED已同意 REJECTED已拒绝',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `handled_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_from_user`(`from_user_id`) USING BTREE,
  INDEX `idx_to_user`(`to_user_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 328 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '好友申请表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_friend_request
-- ----------------------------

-- ----------------------------
-- Table structure for im_group
-- ----------------------------
DROP TABLE IF EXISTS `im_group`;
CREATE TABLE `im_group`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '群组ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '群名称',
  `avatar` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '群头像',
  `owner_id` bigint(20) NOT NULL COMMENT '群主ID',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '群描述',
  `max_members` int(11) NOT NULL DEFAULT 500 COMMENT '最大成员数',
  `all_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '全员禁言: 0否 1是',
  `qrcode_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '群二维码URL',
  `qrcode_expire_time` datetime NULL DEFAULT NULL COMMENT '群二维码过期时间',
  `allow_upload` tinyint(1) NOT NULL DEFAULT 1 COMMENT '允许成员上传文件：0=否, 1=是',
  `show_member_list` tinyint(1) NOT NULL DEFAULT 1 COMMENT '显示成员列表（非群成员可见）：0=否, 1=是',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除: 0否 1是',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_owner_id`(`owner_id`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 50 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_announcement
-- ----------------------------
DROP TABLE IF EXISTS `im_group_announcement`;
CREATE TABLE `im_group_announcement`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '公告ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `sender_id` bigint(20) NOT NULL COMMENT '发送者ID',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '公告内容',
  `type` int(11) NOT NULL DEFAULT 1 COMMENT '公告类型: 1=普通公告, 2=系统公告, 3=活动通知',
  `attachment_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '附件URL（图片、文件等）',
  `is_pinned` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否置顶: 0=否, 1=是',
  `status` int(11) NOT NULL DEFAULT 1 COMMENT '状态: 1=正常, 0=已撤回',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组公告表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_announcement
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_announcement_read
-- ----------------------------
DROP TABLE IF EXISTS `im_group_announcement_read`;
CREATE TABLE `im_group_announcement_read`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `group_id` bigint(20) UNSIGNED NOT NULL COMMENT '群组ID',
  `announcement_id` bigint(20) UNSIGNED NOT NULL COMMENT '公告ID',
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT '用户ID',
  `read_time` datetime NOT NULL COMMENT '已读时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_announcement_user`(`announcement_id`, `user_id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群公告已读状态表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_group_announcement_read
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_blacklist
-- ----------------------------
DROP TABLE IF EXISTS `im_group_blacklist`;
CREATE TABLE `im_group_blacklist`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `user_id` bigint(20) NOT NULL COMMENT '被禁言/被拉黑用户ID',
  `operator_id` bigint(20) NOT NULL COMMENT '操作者ID',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MUTE' COMMENT '类型: MUTE禁言 BLACKLIST拉黑',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '原因',
  `expire_time` datetime NULL DEFAULT NULL COMMENT '过期时间(为空则永久)',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否有效: 0否 1是',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_group_user_type`(`group_id`, `user_id`, `type`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_is_active`(`is_active`) USING BTREE,
  INDEX `idx_expire_time`(`expire_time`) USING BTREE,
  INDEX `fk_group_blacklist_operator`(`operator_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组禁言/黑名单表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_blacklist
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_bot
-- ----------------------------
DROP TABLE IF EXISTS `im_group_bot`;
CREATE TABLE `im_group_bot`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '机器人ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `bot_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '机器人名称',
  `bot_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SERVICE' COMMENT '机器人类型：SERVICE客服/NOTIFY通知/MANAGE管理',
  `avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '机器人头像',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '机器人描述',
  `is_enabled` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否启用：0禁用/1启用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_bot_type`(`bot_type`) USING BTREE,
  INDEX `idx_is_enabled`(`is_enabled`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群机器人表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_bot
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_bot_rule
-- ----------------------------
DROP TABLE IF EXISTS `im_group_bot_rule`;
CREATE TABLE `im_group_bot_rule`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '规则ID',
  `bot_id` bigint(20) NOT NULL COMMENT '机器人ID',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则名称',
  `trigger_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'KEYWORD' COMMENT '触发类型：KEYWORD关键词/COMMAND命令/TIMER定时/REGEX正则',
  `trigger_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '触发内容',
  `reply_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'TEXT' COMMENT '回复类型：TEXT文本/IMAGE图片/CARD卡片/NEWS新闻',
  `reply_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '回复内容',
  `priority` int(11) NOT NULL DEFAULT 0 COMMENT '优先级（数字越大优先级越高）',
  `is_enabled` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否启用：0禁用/1启用',
  `match_mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'CONTAINS' COMMENT '匹配模式：EXACT精确/CONTAINS包含/STARTS_WITH开头/REGEX正则',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_bot_id`(`bot_id`) USING BTREE,
  INDEX `idx_trigger_type`(`trigger_type`) USING BTREE,
  INDEX `idx_priority`(`priority`) USING BTREE,
  INDEX `idx_is_enabled`(`is_enabled`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群机器人规则表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_bot_rule
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_file
-- ----------------------------
DROP TABLE IF EXISTS `im_group_file`;
CREATE TABLE `im_group_file`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '文件ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `file_id` bigint(20) NOT NULL COMMENT '文件资产ID（关联im_file_asset）',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名称',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件类型：image/video/audio/document/other',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小（字节）',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'default' COMMENT '文件分类：default/document/image/video/audio',
  `permission` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ALL' COMMENT '下载权限：ALL=所有人, ADMIN=仅管理员',
  `uploader_id` bigint(20) NOT NULL COMMENT '上传者ID',
  `uploader_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上传者名称',
  `download_count` int(11) NOT NULL DEFAULT 0 COMMENT '下载次数',
  `status` int(11) NOT NULL DEFAULT 1 COMMENT '状态：1=正常, 0=已删除',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组文件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_file
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_log
-- ----------------------------
DROP TABLE IF EXISTS `im_group_log`;
CREATE TABLE `im_group_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `operator_id` bigint(20) NOT NULL COMMENT '操作者ID',
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作者名称',
  `operation_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作类型: ADD_MEMBER添加成员, REMOVE_MEMBER移除成员, CHANGE_ROLE修改角色, MUTE_MEMBER禁言成员, UNMUTE_MEMBER解除禁言, DISMISS_GROUP解散群组, CHANGE_OWNER转让群主, UPDATE_INFO修改群信息',
  `operation_desc` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作描述',
  `target_user_id` bigint(20) NULL DEFAULT NULL COMMENT '目标用户ID（操作对象）',
  `target_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '目标用户名称',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE,
  INDEX `idx_operator_id`(`operator_id`) USING BTREE,
  INDEX `idx_operation_type`(`operation_type`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组管理日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_log
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_member
-- ----------------------------
DROP TABLE IF EXISTS `im_group_member`;
CREATE TABLE `im_group_member`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '成员ID',
  `group_id` bigint(20) NOT NULL COMMENT '群组ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '群昵称',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MEMBER' COMMENT '角色: OWNER群主 ADMIN管理员 MEMBER普通成员',
  `is_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否禁言: 0否 1是',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除: 0否 1是',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '退群时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_group_user`(`group_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_role`(`role`) USING BTREE,
  INDEX `idx_is_muted`(`is_muted`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 397 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群成员表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_group_member
-- ----------------------------

-- ----------------------------
-- Table structure for im_group_permission
-- ----------------------------
DROP TABLE IF EXISTS `im_group_permission`;
CREATE TABLE `im_group_permission`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `group_id` bigint(20) UNSIGNED NOT NULL COMMENT '群组ID',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '角色: OWNER-群主, ADMIN-管理员, MEMBER-普通成员',
  `can_invite` tinyint(1) NOT NULL DEFAULT 0 COMMENT '邀请成员权限: 0=禁止, 1=允许',
  `can_remove` tinyint(1) NOT NULL DEFAULT 0 COMMENT '移除成员权限: 0=禁止, 1=允许',
  `can_mute` tinyint(1) NOT NULL DEFAULT 0 COMMENT '禁言成员权限: 0=禁止, 1=允许',
  `can_announce` tinyint(1) NOT NULL DEFAULT 0 COMMENT '发布公告权限: 0=禁止, 1=允许',
  `can_upload` tinyint(1) NOT NULL DEFAULT 0 COMMENT '上传文件权限: 0=禁止, 1=允许',
  `can_edit_group` tinyint(1) NOT NULL DEFAULT 0 COMMENT '修改群信息权限: 0=禁止, 1=允许',
  `can_kick` tinyint(1) NOT NULL DEFAULT 0 COMMENT '踢人权限: 0=禁止, 1=允许',
  `can_set_admin` tinyint(1) NOT NULL DEFAULT 0 COMMENT '设置管理员权限: 0=禁止, 1=允许',
  `can_disband` tinyint(1) NOT NULL DEFAULT 0 COMMENT '解散群组权限: 0=禁止, 1=允许',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_group_role`(`group_id`, `role`) USING BTREE,
  INDEX `idx_group_id`(`group_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '群组权限配置表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_group_permission
-- ----------------------------

-- ----------------------------
-- Table structure for im_meeting_booking
-- ----------------------------
DROP TABLE IF EXISTS `im_meeting_booking`;
CREATE TABLE `im_meeting_booking`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '预订ID',
  `room_id` bigint(20) NOT NULL COMMENT '会议室ID',
  `booking_user_id` bigint(20) NOT NULL COMMENT '预订人ID',
  `meeting_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '会议主题',
  `meeting_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'REGULAR' COMMENT '会议类型：REGULAR常规 TRAINING培训 INTERVIEW面试 CLIENT客户',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `attendee_count` int(11) NOT NULL DEFAULT 0 COMMENT '参会人数',
  `attendees` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '参会人员ID列表（JSON格式）',
  `agenda` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '会议议程',
  `resources` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '所需资源（JSON格式）',
  `refreshments` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否需要茶水',
  `recording` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否需要录像',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态：PENDING待确认 CONFIRMED已确认 CANCELLED已取消 COMPLETED已完成',
  `check_in_time` datetime NULL DEFAULT NULL COMMENT '签到时间',
  `check_out_time` datetime NULL DEFAULT NULL COMMENT '签退时间',
  `reminder_sent` tinyint(1) NOT NULL DEFAULT 0 COMMENT '提醒是否已发送',
  `feedback` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '会议反馈',
  `rating` int(11) NULL DEFAULT NULL COMMENT '评分（1-5分）',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_room_id`(`room_id`) USING BTREE,
  INDEX `idx_booking_user_id`(`booking_user_id`) USING BTREE,
  INDEX `idx_start_time`(`start_time`) USING BTREE,
  INDEX `idx_end_time`(`end_time`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会议室预订表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_meeting_booking
-- ----------------------------

-- ----------------------------
-- Table structure for im_meeting_room
-- ----------------------------
DROP TABLE IF EXISTS `im_meeting_room`;
CREATE TABLE `im_meeting_room`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '会议室ID',
  `room_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '会议室名称',
  `room_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '会议室编号',
  `department_id` bigint(20) NULL DEFAULT NULL COMMENT '所属部门ID',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '位置',
  `floor` int(11) NULL DEFAULT NULL COMMENT '楼层',
  `capacity` int(11) NOT NULL DEFAULT 0 COMMENT '容纳人数',
  `has_projector` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否有投影仪',
  `has_whiteboard` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否有白板',
  `has_video_conf` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否支持视频会议',
  `has_phone` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否有电话',
  `facilities` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '设施列表（JSON格式）',
  `photos` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '会议室图片（JSON格式）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'AVAILABLE' COMMENT '状态：AVAILABLE可用 MAINTENANCE维护中 DISABLED停用',
  `is_bookable` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否可预订',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '描述',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_room_number`(`room_number`) USING BTREE,
  INDEX `idx_department_id`(`department_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会议室表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_meeting_room
-- ----------------------------

-- ----------------------------
-- Table structure for im_message
-- ----------------------------
DROP TABLE IF EXISTS `im_message`;
CREATE TABLE `im_message`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '消息ID',
  `client_msg_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户端消息ID(用于去重和状态追踪)',
  `send_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '发送状态: PENDING待发送 SENDING发送中 SENT已发送 DELIVERED已送达 FAILED发送失败',
  `send_retry_count` int(11) NOT NULL DEFAULT 0 COMMENT '发送重试次数',
  `send_error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发送错误码',
  `send_error_msg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发送错误信息',
  `delivered_time` datetime NULL DEFAULT NULL COMMENT '送达时间',
  `conversation_id` bigint(20) NOT NULL COMMENT '会话ID',
  `sender_id` bigint(20) NOT NULL COMMENT '发送者ID',
  `message_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '消息类型: TEXT文本 IMAGE图片 VIDEO视频 AUDIO音频 FILE文件',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '消息内容',
  `reply_to_message_id` bigint(20) NULL DEFAULT NULL COMMENT '回复的消息ID',
  `forward_from_message_id` bigint(20) NULL DEFAULT NULL COMMENT '转发来源消息ID',
  `file_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件URL',
  `file_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件名',
  `file_size` bigint(20) NULL DEFAULT NULL COMMENT '文件大小(字节)',
  `sensitive_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'NORMAL' COMMENT '敏感级别: NORMAL普通 SENSITIVE敏感 HIGH高级',
  `is_revoked` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否撤回: 0否 1是',
  `is_edited` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已编辑(0否 1是)',
  `edited_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '编辑后的内容',
  `edit_count` int(11) NOT NULL DEFAULT 0 COMMENT '编辑次数',
  `edit_time` datetime NULL DEFAULT NULL COMMENT '最后编辑时间',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除(0否 1是)',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `revoked_time` datetime NULL DEFAULT NULL COMMENT '撤回时间',
  `revoker_id` bigint(20) NULL DEFAULT NULL COMMENT '撤回者ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `is_encrypted` tinyint(4) NULL DEFAULT 0 COMMENT 'E2E encrypted flag',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '版本号（乐观锁）',
  `encryption_key_version` int(11) NULL DEFAULT NULL COMMENT 'Encryption key version',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_sender_id`(`sender_id`) USING BTREE,
  INDEX `idx_message_type`(`message_type`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `idx_is_revoked`(`is_revoked`) USING BTREE,
  INDEX `idx_conversation_time`(`conversation_id`, `create_time`) USING BTREE,
  INDEX `idx_is_edited`(`is_edited`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE,
  INDEX `idx_client_msg_id`(`client_msg_id`) USING BTREE,
  INDEX `idx_send_status`(`send_status`) USING BTREE,
  INDEX `idx_message_content_prefix`(`content`(255)) USING BTREE,
  INDEX `idx_message_create_time`(`create_time`) USING BTREE,
  INDEX `idx_message_sender_time`(`sender_id`, `create_time`) USING BTREE,
  INDEX `idx_message_conversation_time`(`conversation_id`, `create_time`) USING BTREE,
  INDEX `idx_reply_to`(`reply_to_message_id`) USING BTREE,
  INDEX `idx_forward_from`(`forward_from_message_id`) USING BTREE,
  INDEX `idx_sensitive_level`(`sensitive_level`) USING BTREE,
  INDEX `idx_conv_time_type`(`conversation_id`, `create_time`, `message_type`) USING BTREE,
  FULLTEXT INDEX `ft_content_cn`(`content`) WITH PARSER `ngram`
) ENGINE = InnoDB AUTO_INCREMENT = 3842 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '消息表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_message
-- ----------------------------

-- ----------------------------
-- Table structure for im_message_ack
-- ----------------------------
DROP TABLE IF EXISTS `im_message_ack`;
CREATE TABLE `im_message_ack`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT '用户ID',
  `message_id` bigint(20) UNSIGNED NOT NULL COMMENT '消息ID',
  `conversation_id` bigint(20) UNSIGNED NOT NULL COMMENT '会话ID',
  `client_msg_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户端消息ID',
  `ack_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'deliver' COMMENT 'ACK类型: deliver-送达, receive-接收, read-已读',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `ack_timestamp` bigint(20) UNSIGNED NOT NULL COMMENT 'ACK时间戳(毫秒)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_message`(`user_id`, `message_id`) USING BTREE,
  INDEX `idx_conversation`(`conversation_id`) USING BTREE,
  INDEX `idx_client_msg`(`client_msg_id`) USING BTREE,
  INDEX `idx_ack_timestamp`(`ack_timestamp`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'IM消息确认表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_message_ack
-- ----------------------------

-- ----------------------------
-- Table structure for im_message_edit_history
-- ----------------------------
DROP TABLE IF EXISTS `im_message_edit_history`;
CREATE TABLE `im_message_edit_history`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '历史ID',
  `message_id` bigint(20) NOT NULL COMMENT '消息ID',
  `old_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '编辑前的内容',
  `new_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '编辑后的内容',
  `editor_id` bigint(20) NOT NULL COMMENT '编辑人ID',
  `edit_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '编辑时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_message_id`(`message_id`) USING BTREE,
  INDEX `idx_editor_id`(`editor_id`) USING BTREE,
  INDEX `idx_edit_time`(`edit_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 181 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '消息编辑历史表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_message_edit_history
-- ----------------------------

-- ----------------------------
-- Table structure for im_message_favorite
-- ----------------------------
DROP TABLE IF EXISTS `im_message_favorite`;
CREATE TABLE `im_message_favorite`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '收藏ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `message_id` bigint(20) NOT NULL COMMENT '消息ID',
  `conversation_id` bigint(20) NOT NULL COMMENT '会话ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '收藏备注',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标签（多个标签用逗号分隔）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '收藏时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_message`(`user_id`, `message_id`) USING BTREE COMMENT '同一用户对同一消息只能收藏一次',
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_conversation_id`(`conversation_id`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `fk_favorite_message`(`message_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '消息收藏表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_message_favorite
-- ----------------------------

-- ----------------------------
-- Table structure for im_message_marker
-- ----------------------------
DROP TABLE IF EXISTS `im_message_marker`;
CREATE TABLE `im_message_marker`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '标记ID',
  `message_id` bigint(20) NULL DEFAULT NULL COMMENT '消息ID',
  `conversation_id` bigint(20) NULL DEFAULT NULL COMMENT '会话ID',
  `user_id` bigint(20) NULL DEFAULT NULL COMMENT '用户ID',
  `marker_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'TODO' COMMENT '标记类型：FLAG标记, TODO待办, IMPORTANT重要',
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标记颜色',
  `remind_time` datetime NULL DEFAULT NULL COMMENT '提醒时间',
  `todo_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'PENDING' COMMENT '待办状态：PENDING待办, DONE已完成',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `done_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_message_id`(`message_id`) USING BTREE,
  INDEX `idx_conversation_id`(`conversation_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_marker_type`(`marker_type`) USING BTREE,
  INDEX `idx_user_type`(`user_id`, `marker_type`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '消息标记表' ROW_FORMAT = Dynamic;

