-- ----------------------------
-- Table structure for im_notification_setting
-- ----------------------------
DROP TABLE IF EXISTS `im_notification_setting`;
CREATE TABLE `im_notification_setting`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '设置ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `enabled` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否启用通知',
  `desktop_notification` tinyint(1) NOT NULL DEFAULT 1 COMMENT '桌面通知',
  `sound_enabled` tinyint(1) NOT NULL DEFAULT 1 COMMENT '声音提醒',
  `sound_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'default' COMMENT '声音类型：default/silent/custom',
  `custom_sound_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '自定义声音URL',
  `show_preview` tinyint(1) NOT NULL DEFAULT 1 COMMENT '显示消息预览',
  `dnd_enabled` tinyint(1) NOT NULL DEFAULT 0 COMMENT '免打扰模式',
  `dnd_start_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '22:00' COMMENT '免打扰开始时间',
  `dnd_end_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '08:00' COMMENT '免打扰结束时间',
  `mention_only` tinyint(1) NOT NULL DEFAULT 0 COMMENT '仅接收@提及',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_notification`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户通知设置表' ROW_FORMAT = Dynamic;

