  `nudger_id` bigint(20) NOT NULL COMMENT '发起者用户ID',
  `nudged_user_id` bigint(20) NOT NULL COMMENT '被拍用户ID',
  `nudge_count` int(11) NOT NULL DEFAULT 1 COMMENT '连续拍拍次数',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_conversation`(`conversation_id`) USING BTREE,
  INDEX `idx_nudger`(`nudger_id`) USING BTREE,
  INDEX `idx_nudged`(`nudged_user_id`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 41 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '拍一拍互动记录表' ROW_FORMAT = Dynamic;

