  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `nudge_enabled` tinyint(4) NOT NULL DEFAULT 1 COMMENT '是否允许被拍：0否 1是',
  `nudge_sound_enabled` tinyint(4) NOT NULL DEFAULT 1 COMMENT '是否播放声音：0否 1是',
  `nudge_vibration_enabled` tinyint(4) NOT NULL DEFAULT 1 COMMENT '是否震动：0否 1是',
  `cooldown_seconds` int(11) NOT NULL DEFAULT 30 COMMENT '冷却时间（秒），同一对用户在此时间内只能拍一次',
  `max_continuous_count` int(11) NOT NULL DEFAULT 3 COMMENT '最大连续拍拍次数',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '拍一拍用户配置表' ROW_FORMAT = Dynamic;

