  `permission_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '权限编码（唯一标识）',
  `permission_type` tinyint(1) NULL DEFAULT 1 COMMENT '权限类型：1=菜单 2=按钮',
