-- ----------------------------
-- Table structure for im_role
-- ----------------------------
DROP TABLE IF EXISTS `im_role`;
CREATE TABLE `im_role`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '角色ID',
  `role_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '角色名称',
  `role_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '角色编码（唯一标识）',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '角色描述',
  `data_scope` tinyint(1) NULL DEFAULT 1 COMMENT '数据范围：1=全部 2=本部门 3=本部门及子部门 4=仅本人',
  `builtin` tinyint(1) NULL DEFAULT 0 COMMENT '是否系统内置角色：0=否 1=是',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '状态：0=禁用 1=启用',
  `sort_order` int(11) NULL DEFAULT 0 COMMENT '排序',
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '角色颜色（前端展示）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(1) NULL DEFAULT 0 COMMENT '删除标志：0=正常 1=删除',
