  `permission_id` bigint(20) NOT NULL COMMENT '权限ID',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_role_permission`(`role_id`, `permission_id`) USING BTREE,
  INDEX `idx_role_id`(`role_id`) USING BTREE,
  INDEX `idx_permission_id`(`permission_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 133 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '角色权限关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_role_permission
-- ----------------------------

-- ----------------------------
-- Table structure for im_schedule_event
-- ----------------------------
DROP TABLE IF EXISTS `im_schedule_event`;
CREATE TABLE `im_schedule_event`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '日程ID',
  `user_id` bigint(20) NOT NULL COMMENT '创建人ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '日程标题',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '日程描述',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '地点',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `is_all_day` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否全天（0否 1是）',
  `recurrence_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '重复类型（NONE无 DAILY每天 WEEKLY每周 MONTHLY每月 CUSTOM自定义）',
  `recurrence_end_date` date NULL DEFAULT NULL COMMENT '重复结束日期',
  `recurrence_interval` int(11) NULL DEFAULT NULL COMMENT '重复间隔（每N天/周/月）',
  `recurrence_days` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '重复的星期几（1-7，逗号分隔）',
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '显示颜色',
  `visibility` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PRIVATE' COMMENT '可见范围（PRIVATE私有 DEPARTMENT部门 PUBLIC公开）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SCHEDULED' COMMENT '状态（SCHEDULED已安排 CANCELLED已取消 COMPLETED已完成）',
  `reminder_minutes` int(11) NULL DEFAULT NULL COMMENT '提醒时间（分钟，事件开始前多少分钟提醒）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_start_time`(`start_time`) USING BTREE,
  INDEX `idx_end_time`(`end_time`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 45 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '日程事件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_schedule_event
-- ----------------------------

-- ----------------------------
-- Table structure for im_schedule_participant
-- ----------------------------
DROP TABLE IF EXISTS `im_schedule_participant`;
CREATE TABLE `im_schedule_participant`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `event_id` bigint(20) NOT NULL COMMENT '日程ID',
  `user_id` bigint(20) NOT NULL COMMENT '参与人ID',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '参与状态（PENDING待确认 ACCEPTED已接受 DECLINED已拒绝）',
  `response_time` datetime NULL DEFAULT NULL COMMENT '回复时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_event_user`(`event_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '日程参与人表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_schedule_participant
-- ----------------------------

-- ----------------------------
-- Table structure for im_schedule_reminder
-- ----------------------------
DROP TABLE IF EXISTS `im_schedule_reminder`;
CREATE TABLE `im_schedule_reminder`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '提醒ID',
  `event_id` bigint(20) NOT NULL COMMENT '日程ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `reminder_time` datetime NOT NULL COMMENT '提醒时间',
  `is_sent` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已发送（0否 1是）',
  `sent_time` datetime NULL DEFAULT NULL COMMENT '发送时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_event_id`(`event_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_reminder_time`(`reminder_time`) USING BTREE,
  INDEX `idx_is_sent`(`is_sent`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '日程提醒记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_schedule_reminder
-- ----------------------------

-- ----------------------------
-- Table structure for im_scheduled_message
-- ----------------------------
DROP TABLE IF EXISTS `im_scheduled_message`;
CREATE TABLE `im_scheduled_message`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `user_id` bigint(20) NOT NULL COMMENT '鍙戦?鑰呯敤鎴稩D',
  `conversation_id` bigint(20) NOT NULL COMMENT '浼氳瘽ID',
  `message_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '娑堟伅绫诲瀷锛歍EXT/FILE/IMAGE/VOICE/VIDEO',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '娑堟伅鍐呭?',
  `file_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '鏂囦欢URL',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '鏂囦欢鍚',
  `reply_to_message_id` bigint(20) NULL DEFAULT NULL COMMENT '鍥炲?鐨勬秷鎭疘D',
  `scheduled_time` datetime NOT NULL COMMENT '瀹氭椂鍙戦?鏃堕棿',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'PENDING' COMMENT '鐘舵?锛歅ENDING/SENT/FAILED/CANCELLED',
  `sent_message_id` bigint(20) NULL DEFAULT NULL COMMENT '鍙戦?鍚庣殑娑堟伅ID',
  `error_msg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '澶辫触鍘熷洜',
  `retry_count` int(11) NULL DEFAULT 0 COMMENT '閲嶈瘯娆℃暟',
  `sent_time` datetime NULL DEFAULT NULL COMMENT '瀹為檯鍙戦?鏃堕棿',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_status`(`user_id`, `status`) USING BTREE,
  INDEX `idx_scheduled_time`(`scheduled_time`, `status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '瀹氭椂娑堟伅琛' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_scheduled_message
-- ----------------------------

-- ----------------------------
-- Table structure for im_sensitive_event
-- ----------------------------
DROP TABLE IF EXISTS `im_sensitive_event`;
CREATE TABLE `im_sensitive_event`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '事件ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `conversation_id` bigint(20) NULL DEFAULT NULL COMMENT '会话ID',
  `message_id` bigint(20) NULL DEFAULT NULL COMMENT '消息ID',
  `detected_word` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '检测到的敏感词',
  `action` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '处理动作: REJECTED拒绝 MASKED屏蔽 WARNED警告',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_conversation_id`(`conversation_id`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `idx_message_id`(`message_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '敏感事件记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_sensitive_event
-- ----------------------------

-- ----------------------------
-- Table structure for im_sensitive_word
-- ----------------------------
DROP TABLE IF EXISTS `im_sensitive_word`;
CREATE TABLE `im_sensitive_word`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '敏感词ID',
  `word` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '敏感词内容',
  `word_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'OTHER' COMMENT '敏感词类型（POLITICAL政治、VULGAR低俗、VIOLENCE暴力、AD广告、OTHER其他）',
  `level` int(11) NULL DEFAULT 1 COMMENT '敏感级别（1低 2中 3高）',
  `action` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'REPLACE' COMMENT '处理方式（REPLACE替换、REJECT拒绝、WARN警告）',
  `replacement` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '***' COMMENT '替换内容',
  `is_enabled` tinyint(1) NULL DEFAULT 1 COMMENT '是否启用',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_word`(`word`) USING BTREE,
  INDEX `idx_word_type`(`word_type`) USING BTREE,
  INDEX `idx_level`(`level`) USING BTREE,
  INDEX `idx_enabled`(`is_enabled`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '敏感词表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_sensitive_word
-- ----------------------------

-- ----------------------------
-- Table structure for im_session_group
-- ----------------------------
DROP TABLE IF EXISTS `im_session_group`;
CREATE TABLE `im_session_group`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '分组ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `group_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分组名称',
  `sort_order` int(11) NOT NULL DEFAULT 0 COMMENT '排序',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '会话分组表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_session_group
-- ----------------------------

-- ----------------------------
-- Table structure for im_system_config
-- ----------------------------
DROP TABLE IF EXISTS `im_system_config`;
CREATE TABLE `im_system_config`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `config_key` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '配置键',
  `config_value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '配置值',
  `config_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'STRING' COMMENT '配置类型: STRING字符串 NUMBER数字 BOOLEAN布尔',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '描述',
  `status` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态: ACTIVE有效 DISABLED禁用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_config_key`(`config_key`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '系统配置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_system_config
-- ----------------------------

-- ----------------------------
-- Table structure for im_system_notification
-- ----------------------------
DROP TABLE IF EXISTS `im_system_notification`;
CREATE TABLE `im_system_notification`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '通知ID',
  `receiver_id` bigint(20) NOT NULL COMMENT '接收者ID',
  `sender_id` bigint(20) NULL DEFAULT NULL COMMENT '发送者ID(系统通知为NULL)',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '通知类型: SYSTEM系统 APPROVAL审批 MESSAGE消息 GROUP群组 FRIEND好友',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '内容',
  `related_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关联类型: USER MESSAGE GROUP CONVERSATION APPROVAL',
  `related_id` bigint(20) NULL DEFAULT NULL COMMENT '关联ID',
  `is_read` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已读: 0否 1是',
  `read_time` datetime NULL DEFAULT NULL COMMENT '已读时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_receiver_id`(`receiver_id`) USING BTREE,
  INDEX `idx_type`(`type`) USING BTREE,
  INDEX `idx_is_read`(`is_read`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE,
  INDEX `fk_system_notification_sender`(`sender_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1200 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '系统通知表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_system_notification
-- ----------------------------

-- ----------------------------
-- Table structure for im_task
-- ----------------------------
DROP TABLE IF EXISTS `im_task`;
CREATE TABLE `im_task`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `project_id` bigint(20) NULL DEFAULT NULL COMMENT '项目ID（可选，用于项目任务管理）',
  `task_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务编号',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务标题',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '任务描述',
  `creator_id` bigint(20) NOT NULL COMMENT '创建人ID',
  `assignee_id` bigint(20) NULL DEFAULT NULL COMMENT '负责人ID',
  `priority` tinyint(1) NOT NULL DEFAULT 2 COMMENT '优先级（1=低 2=中 3=高 4=紧急）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态：PENDING待办 IN_PROGRESS进行中 COMPLETED已完成 CANCELLED已取消 BLOCKED阻塞',
  `task_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PERSONAL' COMMENT '任务类型：PERSONAL个人 TEAM团队 PROJECT项目',
  `start_date` date NULL DEFAULT NULL COMMENT '开始日期',
  `due_date` date NULL DEFAULT NULL COMMENT '截止日期',
  `estimated_hours` int(11) NULL DEFAULT NULL COMMENT '预估工时（小时）',
  `actual_hours` int(11) NULL DEFAULT NULL COMMENT '实际工时（小时）',
  `completion_percent` int(11) NOT NULL DEFAULT 0 COMMENT '完成进度（0-100）',
  `parent_id` bigint(20) NULL DEFAULT NULL COMMENT '父任务ID（用于子任务）',
  `has_subtask` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否有子任务',
  `attachments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '附件（JSON格式存储附件列表）',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标签（多个标签用逗号分隔）',
  `followers` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关注人ID列表（JSON数组）',
  `remind_time` datetime NULL DEFAULT NULL COMMENT '提醒时间',
  `remind_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'NONE' COMMENT '提醒类型：NONE无 EMAIL邮件 SMS短信 DING钉钉',
  `repeat_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'NONE' COMMENT '重复类型：NONE无 DAILY每日 WEEKLY每周 MONTHLY每月',
  `completed_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `department_id` bigint(20) NULL DEFAULT NULL COMMENT '部门ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_number`(`task_number`) USING BTREE,
  INDEX `idx_creator_id`(`creator_id`) USING BTREE,
  INDEX `idx_assignee_id`(`assignee_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_priority`(`priority`) USING BTREE,
  INDEX `idx_due_date`(`due_date`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE,
  INDEX `idx_department_id`(`department_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_task
-- ----------------------------

-- ----------------------------
-- Table structure for im_task_attachment
-- ----------------------------
DROP TABLE IF EXISTS `im_task_attachment`;
CREATE TABLE `im_task_attachment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '附件ID',
  `task_id` bigint(20) NOT NULL COMMENT '任务ID',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名',
  `file_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件URL',
  `file_size` bigint(20) NOT NULL COMMENT '文件大小（字节）',
  `file_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件类型',
  `upload_user_id` bigint(20) NOT NULL COMMENT '上传用户ID',
  `upload_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id`) USING BTREE,
  INDEX `idx_upload_user_id`(`upload_user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务附件表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_task_attachment
-- ----------------------------

-- ----------------------------
-- Table structure for im_task_comment
-- ----------------------------
DROP TABLE IF EXISTS `im_task_comment`;
CREATE TABLE `im_task_comment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '评论ID',
  `task_id` bigint(20) NOT NULL COMMENT '任务ID',
  `user_id` bigint(20) NOT NULL COMMENT '评论用户ID',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评论内容',
  `reply_to_user_id` bigint(20) NULL DEFAULT NULL COMMENT '回复给用户ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除（0否 1是）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务评论表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_task_comment
-- ----------------------------

-- ----------------------------
-- Table structure for im_todo_item
-- ----------------------------
DROP TABLE IF EXISTS `im_todo_item`;
CREATE TABLE `im_todo_item`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '待办ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标题',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '描述',
  `priority` tinyint(1) NOT NULL DEFAULT 1 COMMENT '优先级: 1低 2中 3高',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态: PENDING待办 IN_PROGRESS进行中 COMPLETED已完成 CANCELLED已取消',
  `due_date` date NULL DEFAULT NULL COMMENT '截止日期',
  `completed_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `del_flag` int(11) NULL DEFAULT 0 COMMENT '删除标志（0代表存在 1代表删除）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_priority`(`priority`) USING BTREE,
  INDEX `idx_due_date`(`due_date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 27 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '待办事项表' ROW_FORMAT = DYNAMIC;

