-- ----------------------------
-- Table structure for im_user_session
-- ----------------------------
DROP TABLE IF EXISTS `im_user_session`;
CREATE TABLE `im_user_session`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `conversation_id` bigint(20) NOT NULL COMMENT '会话ID',
  `is_pinned` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否置顶',
  `pinned_time` datetime NULL DEFAULT NULL COMMENT '置顶时间',
  `is_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否免打扰',
  `is_archived` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否归档',
  `unread_count` int(11) NOT NULL DEFAULT 0 COMMENT '未读消息数',
  `last_read_message_id` bigint(20) NULL DEFAULT NULL COMMENT '最后已读消息ID',
  `draft_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '草稿内容',
  `draft_time` datetime NULL DEFAULT NULL COMMENT '草稿时间',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除',
  `deleted_time` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_conversation`(`user_id`, `conversation_id`) USING BTREE,
  INDEX `idx_conversation_id`(`conversation_id`) USING BTREE,
  INDEX `idx_is_pinned`(`user_id`, `is_pinned`) USING BTREE,
  INDEX `idx_update_time`(`user_id`, `update_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户会话状态表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_user_session
-- ----------------------------

-- ----------------------------
-- Table structure for im_user_setting
-- ----------------------------
DROP TABLE IF EXISTS `im_user_setting`;
CREATE TABLE `im_user_setting`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '设置ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `setting_key` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设置键',
  `setting_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '设置值',
  `setting_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NOTIFICATION' COMMENT '设置类型: NOTIFICATION通知 PRIVACY隐私 DISPLAY显示',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_setting_key`(`user_id`, `setting_key`) USING BTREE,
  INDEX `idx_setting_type`(`setting_type`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1084 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户设置表' ROW_FORMAT = DYNAMIC;

