-- ----------------------------
-- Table structure for im_video_call
-- ----------------------------
DROP TABLE IF EXISTS `im_video_call`;
CREATE TABLE `im_video_call`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `caller_id` bigint(20) NOT NULL COMMENT '发起者ID',
  `callee_id` bigint(20) NOT NULL COMMENT '接收者ID',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'VOICE语音 VIDEO视频',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT 'PENDING进行中 ACCEPTED接通 REJECTED拒绝 ENDED结束',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
  `duration` int(11) NULL DEFAULT NULL COMMENT '时长（秒）',
  `reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '结束原因',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_caller_id`(`caller_id`) USING BTREE,
  INDEX `idx_callee_id`(`callee_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '音视频通话记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_video_call
-- ----------------------------

-- ----------------------------
-- Table structure for im_video_call_participant
-- ----------------------------
DROP TABLE IF EXISTS `im_video_call_participant`;
CREATE TABLE `im_video_call_participant`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '参与者ID',
  `call_id` bigint(20) NOT NULL COMMENT '通话ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名称（冗余）',
  `user_avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户头像（冗余）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'INVITED' COMMENT '参与状态：INVITED已邀请, JOINED已加入, LEFT已离开, REJECTED已拒绝',
  `join_time` datetime NULL DEFAULT NULL COMMENT '加入时间',
  `leave_time` datetime NULL DEFAULT NULL COMMENT '离开时间',
  `is_muted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否静音',
  `is_camera_off` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否关闭摄像头',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_call_user`(`call_id`, `user_id`) USING BTREE,
  INDEX `idx_call_id`(`call_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频通话参与者表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_video_call_participant
-- ----------------------------

-- ----------------------------
-- Table structure for im_video_meeting
-- ----------------------------
DROP TABLE IF EXISTS `im_video_meeting`;
CREATE TABLE `im_video_meeting`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '会议ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '会议标题',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '会议描述',
  `host_id` bigint(20) NOT NULL COMMENT '发起人ID',
  `host_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发起人名称',
  `meeting_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MEETING' COMMENT '会议类型：MEETING会议 WEBINAR网络研讨会',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SCHEDULED' COMMENT '会议状态：SCHEDULED预定 IN_PROGRESS进行中 ENDED已结束 CANCELLED已取消',
  `scheduled_start_time` datetime NULL DEFAULT NULL COMMENT '预定开始时间',
  `scheduled_end_time` datetime NULL DEFAULT NULL COMMENT '预定结束时间',
  `actual_start_time` datetime NULL DEFAULT NULL COMMENT '实际开始时间',
  `actual_end_time` datetime NULL DEFAULT NULL COMMENT '实际结束时间',
  `duration` int(11) NULL DEFAULT NULL COMMENT '会议时长（分钟）',
  `max_participants` int(11) NULL DEFAULT 100 COMMENT '最大参与人数',
  `current_participants` int(11) NULL DEFAULT 0 COMMENT '当前参与人数',
  `require_password` tinyint(1) NULL DEFAULT 0 COMMENT '是否需要密码',
  `meeting_password` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '会议密码',
  `mute_on_join` tinyint(1) NULL DEFAULT 0 COMMENT '是否开启入会静音',
  `allow_screen_share` tinyint(1) NULL DEFAULT 1 COMMENT '是否允许屏幕共享',
  `allow_record` tinyint(1) NULL DEFAULT 0 COMMENT '是否允许录制',
  `record_file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '录制文件路径',
  `room_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '房间ID（用于WebRTC）',
  `meeting_link` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '会议链接',
  `del_flag` tinyint(1) NULL DEFAULT 0 COMMENT '是否已删除',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_host_id`(`host_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `idx_create_time`(`create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频会议表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_video_meeting
-- ----------------------------

-- ----------------------------
-- Table structure for im_video_meeting_participant
-- ----------------------------
DROP TABLE IF EXISTS `im_video_meeting_participant`;
CREATE TABLE `im_video_meeting_participant`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '参与者ID',
  `meeting_id` bigint(20) NOT NULL COMMENT '会议ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名称',
  `user_avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户头像',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'PARTICIPANT' COMMENT '角色：HOST主持人 CO_HOST联席主持人 PARTICIPANT参与者',
  `join_time` datetime NULL DEFAULT NULL COMMENT '加入时间',
  `leave_time` datetime NULL DEFAULT NULL COMMENT '离开时间',
  `is_muted` tinyint(1) NULL DEFAULT 0 COMMENT '是否静音',
  `video_enabled` tinyint(1) NULL DEFAULT 1 COMMENT '是否开启视频',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_meeting_user`(`meeting_id`, `user_id`) USING BTREE,
  INDEX `idx_meeting_id`(`meeting_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频会议参与者表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of im_video_meeting_participant
-- ----------------------------

-- ----------------------------
-- Table structure for im_voice_transcript
-- ----------------------------
DROP TABLE IF EXISTS `im_voice_transcript`;
CREATE TABLE `im_voice_transcript`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `message_id` bigint(20) NOT NULL COMMENT '消息ID',
  `voice_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '原始语音文件URL',
  `duration` int(11) NOT NULL COMMENT '语音时长（秒）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '转换状态：PENDING待处理, PROCESSING处理中, SUCCESS成功, FAILED失败',
  `transcript_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '识别文本结果',
  `language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'zh-CN' COMMENT '语言类型：zh-CN中文, en-US英文等',
  `confidence` int(11) NULL DEFAULT NULL COMMENT '置信度（0-100）',
  `provider` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '第三方服务商：ALIYUN阿里云, XUNFEI讯飞, TENCENT腾讯',
  `request_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '服务请求ID',
  `error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '错误码',
  `error_msg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '错误信息',
  `process_duration` bigint(20) NULL DEFAULT NULL COMMENT '处理时长（毫秒）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `complete_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_message_id`(`message_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '语音转文字记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_voice_transcript
-- ----------------------------

-- ----------------------------
-- Table structure for im_work_report
-- ----------------------------
DROP TABLE IF EXISTS `im_work_report`;
CREATE TABLE `im_work_report`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `user_id` bigint(20) NOT NULL COMMENT '提交人ID',
  `report_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '日志类型（DAILY日报 WEEKLY周报 MONTHLY月报）',
  `report_date` date NOT NULL COMMENT '报告日期',
  `work_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '工作内容',
  `completion_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'COMPLETED' COMMENT '完成状态（COMPLETED已完成 IN_PROGRESS进行中 PENDING待处理）',
  `tomorrow_plan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '明日计划',
  `issues` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '遇到的问题',
  `attachments` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '附件（多个附件用逗号分隔）',
  `work_hours` decimal(4, 2) NULL DEFAULT NULL COMMENT '工作时长（小时）',
  `visibility` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'DEPARTMENT' COMMENT '可见范围（PRIVATE私有 DEPARTMENT部门 PUBLIC公开）',
  `submit_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '提交时间',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SUBMITTED' COMMENT '状态（DRAFT草稿 SUBMITTED已提交 APPROVED已审批 REJECTED已退回）',
  `approver_id` bigint(20) NULL DEFAULT NULL COMMENT '审批人ID',
  `approve_time` datetime NULL DEFAULT NULL COMMENT '审批时间',
  `approve_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审批备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_report_type`(`report_type`) USING BTREE,
  INDEX `idx_report_date`(`report_date`) USING BTREE,
  INDEX `idx_submit_time`(`submit_time`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_status_username`(`status`, `username`) USING BTREE,
  INDEX `fk_work_report_approver`(`approver_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 44 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '工作日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_work_report
-- ----------------------------

-- ----------------------------
-- Table structure for im_work_report_comment
-- ----------------------------
DROP TABLE IF EXISTS `im_work_report_comment`;
CREATE TABLE `im_work_report_comment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '评论ID',
  `report_id` bigint(20) NOT NULL COMMENT '日志ID',
  `user_id` bigint(20) NOT NULL COMMENT '评论人ID',
  `content` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评论内容',
  `parent_id` bigint(20) NULL DEFAULT NULL COMMENT '父评论ID（回复）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '评论时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_report_id`(`report_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '工作日志评论表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_work_report_comment
-- ----------------------------

-- ----------------------------
-- Table structure for im_work_report_like
-- ----------------------------
DROP TABLE IF EXISTS `im_work_report_like`;
CREATE TABLE `im_work_report_like`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '点赞ID',
  `report_id` bigint(20) NOT NULL COMMENT '日志ID',
  `user_id` bigint(20) NOT NULL COMMENT '点赞人ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '点赞时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_report_user`(`report_id`, `user_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '工作日志点赞表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of im_work_report_like
-- ----------------------------

