INSERT INTO `im_email_template` VALUES (1, '入职欢迎', 'WELCOME', '欢迎加入${companyName}大家庭！', '<html><body><h1>亲爱的${userName}，</h1><p>欢迎加入<strong>${companyName}</strong>！</p><p>您的入职信息如下：</p><ul><li>入职日期：${joinDate}</li><li>部门：${department}</li><li>职位：${position}</li></ul><p>如有任何问题，请联系HR：${hrName} (${hrEmail})</p><p>祝您工作愉快！</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"companyName\",\"label\":\"公司名称\"},{\"name\":\"userName\",\"label\":\"员工姓名\"},{\"name\":\"joinDate\",\"label\":\"入职日期\"},{\"name\":\"department\",\"label\":\"部门\"},{\"name\":\"position\",\"label\":\"职位\"},{\"name\":\"hrName\",\"label\":\"HR姓名\"},{\"name\":\"hrEmail\",\"label\":\"HR邮箱\"}]', 1, 0, '入职', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '新员工入职欢迎邮件模板');
INSERT INTO `im_email_template` VALUES (2, '会议通知', 'MEETING_NOTICE', '【会议通知】${meetingTitle}', '<html><body><h2>会议通知</h2><p>尊敬的${userName}，</p><p>您好！您有一场会议需要参加：</p><ul><li><strong>会议主题：</strong>${meetingTitle}</li><li><strong>会议时间：</strong>${meetingTime}</li><li><strong>会议地点：</strong>${meetingRoom}</li><li><strong>主持人：</strong>${host}</li><li><strong>参会人员：</strong>${participants}</li></ul><p><strong>会议内容：</strong></p><p>${meetingContent}</p><p>请准时参加，如有特殊情况请提前联系主持人。</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"收件人姓名\"},{\"name\":\"meetingTitle\",\"label\":\"会议标题\"},{\"name\":\"meetingTime\",\"label\":\"会议时间\"},{\"name\":\"meetingRoom\",\"label\":\"会议地点\"},{\"name\":\"host\",\"label\":\"主持人\"},{\"name\":\"participants\",\"label\":\"参会人员\"},{\"name\":\"meetingContent\",\"label\":\"会议内容\"}]', 1, 0, '通知', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '会议通知邮件模板');
INSERT INTO `im_email_template` VALUES (3, '项目提醒', 'PROJECT_REMINDER', '【项目提醒】${projectName} - ${reminderType}', '<html><body><h2>项目提醒</h2><p>亲爱的${userName}，</p><p>关于项目 <strong>${projectName}</strong> 的提醒：</p><ul><li><strong>提醒类型：</strong>${reminderType}</li><li><strong>截止日期：</strong>${deadline}</li><li><strong>相关任务：</strong>${taskName}</li></ul><p><strong>详细内容：</strong></p><p>${content}</p><p>请及时处理，谢谢！</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"收件人姓名\"},{\"name\":\"projectName\",\"label\":\"项目名称\"},{\"name\":\"reminderType\",\"label\":\"提醒类型\"},{\"name\":\"deadline\",\"label\":\"截止日期\"},{\"name\":\"taskName\",\"label\":\"任务名称\"},{\"name\":\"content\",\"label\":\"详细内容\"}]', 1, 0, '提醒', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '项目进度提醒邮件模板');
INSERT INTO `im_email_template` VALUES (4, '系统公告', 'SYSTEM_ANNOUNCEMENT', '【系统公告】${title}', '<html><body><div style=\"background:#f5f5f5;padding:20px;\"><h2 style=\"color:#333;\">📢 系统公告</h2><h3 style=\"color:#666;\">${title}</h3><div style=\"background:#fff;padding:20px;margin-top:15px;border-radius:5px;\"><p>${content}</p></div><p style=\"color:#999;font-size:12px;margin-top:20px;\">发布时间：${publishTime}</p></div></body></html>', 'SYSTEM', 'ALL', '[{\"name\":\"title\",\"label\":\"公告标题\"},{\"name\":\"content\",\"label\":\"公告内容\"},{\"name\":\"publishTime\",\"label\":\"发布时间\"}]', 1, 0, '公告', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '系统公告邮件模板');
INSERT INTO `im_email_template` VALUES (5, '请假审批', 'LEAVE_APPROVAL', '【审批通知】您的请假申请已${approvalResult}', '<html><body><h2>请假审批结果</h2><p>尊敬的${userName}，</p><p>您的请假申请已处理：</p><ul><li><strong>请假类型：</strong>${leaveType}</li><li><strong>开始时间：</strong>${startTime}</li><li><strong>结束时间：</strong>${endTime}</li><li><strong>请假原因：</strong>${reason}</li><li><strong>审批结果：</strong><span style=\"color:${resultColor};\">${approvalResult}</span></li><li><strong>审批意见：</strong>${comment}</li></ul><p>如有疑问，请联系HR。</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"申请人姓名\"},{\"name\":\"leaveType\",\"label\":\"请假类型\"},{\"name\":\"startTime\",\"label\":\"开始时间\"},{\"name\":\"endTime\",\"label\":\"结束时间\"},{\"name\":\"reason\",\"label\":\"请假原因\"},{\"name\":\"approvalResult\",\"label\":\"审批结果\"},{\"name\":\"comment\",\"label\":\"审批意见\"},{\"name\":\"resultColor\",\"label\":\"结果颜色\"}]', 1, 0, '审批', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '请假审批通知模板');
INSERT INTO `im_email_template` VALUES (6, '生日祝福', 'BIRTHDAY_WISH', '🎂 祝${userName}生日快乐！', '<html><body style=\"text-align:center;\"><div style=\"max-width:600px;margin:0 auto;padding:20px;\"><h1 style=\"color:#ff6b6b;\">🎂 生日快乐！</h1><div style=\"background:linear-gradient(135deg,#667eea,#764ba2);color:white;padding:40px;border-radius:20px;margin:20px 0;\"><h2>亲爱的 ${userName}，</h2><p style=\"font-size:18px;\">在这特别的日子里，</p><p style=\"font-size:24px;font-weight:bold;\">祝您生日快乐！</p><p style=\"font-size:18px;\">愿您天天开心，工作顺利！</p></div><p style=\"color:#666;\">— 来自 ${companyName} 大家庭的祝福</p></div></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"员工姓名\"},{\"name\":\"companyName\",\"label\":\"公司名称\"}]', 1, 0, '祝福', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '员工生日祝福邮件模板');
INSERT INTO `im_email_template` VALUES (7, '绩效考核', 'PERFORMANCE_REVIEW', '【绩效考核】${year}年度绩效评估通知', '<html><body><h2>年度绩效评估</h2><p>尊敬的${userName}，</p><p>${year}年度绩效评估已经开始，请您尽快完成以下事项：</p><ul><li><strong>评估周期：</strong>${year}年1月1日 - ${year}年12月31日</li><li><strong>自评截止：</strong>${selfReviewDeadline}</li><li><strong>评估人：</strong>${evaluator}</li></ul><p>请登录系统完成自评，逾期将影响评估结果。</p><p>如有疑问，请联系HR。</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"员工姓名\"},{\"name\":\"year\",\"label\":\"年度\"},{\"name\":\"selfReviewDeadline\",\"label\":\"自评截止日期\"},{\"name\":\"evaluator\",\"label\":\"评估人\"}]', 1, 0, '通知', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '绩效考核评估通知模板');
INSERT INTO `im_email_template` VALUES (8, '费用报销', 'EXPENSE_APPROVAL', '【报销通知】您的报销申请已${approvalResult}', '<html><body><h2>费用报销审批结果</h2><p>尊敬的${userName}，</p><p>您的报销申请已处理：</p><ul><li><strong>报销类型：</strong>${expenseType}</li><li><strong>报销金额：</strong>¥${amount}</li><li><strong>费用日期：</strong>${expenseDate}</li><li><strong>审批结果：</strong>${approvalResult}</li><li><strong>审批意见：</strong>${comment}</li></ul><p>款项将在3-5个工作日内到账。</p></body></html>', 'SYSTEM', 'INTERNAL', '[{\"name\":\"userName\",\"label\":\"申请人姓名\"},{\"name\":\"expenseType\",\"label\":\"报销类型\"},{\"name\":\"amount\",\"label\":\"报销金额\"},{\"name\":\"expenseDate\",\"label\":\"费用日期\"},{\"name\":\"approvalResult\",\"label\":\"审批结果\"},{\"name\":\"comment\",\"label\":\"审批意见\"}]', 1, 0, '审批', 'admin', '2026-02-27 14:06:37', '', '2026-02-27 14:06:37', '费用报销审批通知模板');
