INSERT INTO `im_message_edit_history` VALUES (1, 1, '你好，李四！最近工作怎么样？', '你好，李四！最近工作怎么样了？', 1, '2026-01-30 10:01:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (2, 2, '挺好的，张三！你呢？', '挺好的，张三！你最近怎么样？', 2, '2026-01-30 10:02:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (3, 3, '王五，明天的会议准备好了吗？', '王五，后天的会议准备好了吗？', 1, '2026-01-30 10:03:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (4, 4, '准备好了，资料都已经整理好了。', '准备好了，资料都已经整理完毕。', 3, '2026-01-30 10:04:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (5, 5, '赵六，产品需求文档什么时候能给我？', '赵六，产品需求文档什么时候能发给我？', 1, '2026-01-30 10:05:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (10, 10, '已经完成了基础框架，正在测试中。', '已经完成了基础框架，正在进行测试。', 1, '2026-01-30 10:10:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (11, 11, '周八，设计稿什么时候能出来？', '周八，设计稿什么时候能完成？', 2, '2026-01-30 10:11:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (12, 12, '明天上午就能给你，已经差不多了。', '明天上午就能给你，已经基本完成。', 6, '2026-01-30 10:12:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (13, 13, '吴九，后端接口开发得怎么样了？', '吴九，后端接口开发进展如何？', 2, '2026-01-30 10:13:00', '2026-01-30 16:12:02');
INSERT INTO `im_message_edit_history` VALUES (14, 14, '已经完成了80%，预计明天能全部完成。', '已经完成了80%，预计明天全部完成。', 7, '2026-01-30 10:14:00', '2026-01-30 16:12:02');
